mapper.select:
SELECT u.*, d.dept_name, p.position_name FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id LEFT JOIN sys_position p ON u.position_id = p.id WHERE u.del_flag = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.real_name LIKE CONCAT('%', #{realName}, '%')
AND u.dept_id = #{deptId}
AND u.status = #{status}
ORDER BY u.create_time DESC
